#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Upload a file to DBFS
 *
 * This example demonstrates:
 * - Creating directories in DBFS
 * - Uploading file content to DBFS
 * - Writing data in chunks
 * - Verifying file upload
 * - Listing DBFS contents
 *
 * Prerequisites:
 * - DATABRICKS_HOST environment variable
 * - Valid authentication (PAT, OAuth M2M, or other)
 *
 * Usage:
 *   npx ts-node examples/workspace/files/dbfs-upload.ts
 */

import {WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const client = new WorkspaceClient({});

    const dbfsPath = `/tmp/sdk-example-${Date.now()}`;
    const fileName = "example.txt";
    const fullPath = `${dbfsPath}/${fileName}`;

    console.log(`Uploading file to DBFS: ${fullPath}`);

    try {
        // Create directory
        console.log(`\nCreating directory: ${dbfsPath}`);

        await client.dbfs.mkdirs({
            path: dbfsPath,
        });

        console.log(`✓ Directory created`);

        // Create file content
        const content = `Hello from Databricks SDK!
This file was uploaded using the JavaScript SDK.
Timestamp: ${new Date().toISOString()}

This demonstrates:
- File upload to DBFS
- Directory creation
- Content writing
`;

        // Convert content to base64
        const base64Content = Buffer.from(content).toString("base64");

        // Put file (simple upload for small files)
        console.log(`\nUploading file...`);

        await client.dbfs.put({
            path: fullPath,
            contents: base64Content,
            overwrite: true,
        });

        console.log(`✓ File uploaded successfully`);

        // Get file status
        const status = await client.dbfs.getStatus({
            path: fullPath,
        });

        console.log(`\nFile Status:`);
        console.log(`  Path: ${status.path}`);
        console.log(`  File Size: ${status.file_size} bytes`);
        console.log(`  Is Directory: ${status.is_dir}`);
        console.log(
            `  Modification Time: ${status.modification_time ? new Date(status.modification_time).toISOString() : "N/A"}`
        );

        // List directory contents
        console.log(`\nListing directory: ${dbfsPath}`);

        const files: any[] = [];
        for await (const file of client.dbfs.list({
            path: dbfsPath,
        })) {
            files.push({
                "Path": file.path,
                "Size (bytes)": file.file_size,
                "Is Directory": file.is_dir ? "Yes" : "No",
            });
        }

        if (files.length > 0) {
            console.table(files);
        } else {
            console.log(`  No files found`);
        }

        // Example: Upload another file with different content
        console.log(`\n--- Uploading JSON file ---`);

        const jsonPath = `${dbfsPath}/data.json`;
        const jsonData = {
            message: "This is JSON data",
            timestamp: new Date().toISOString(),
            numbers: [1, 2, 3, 4, 5],
            metadata: {
                source: "databricks-sdk-js",
                version: "1.0.0",
            },
        };

        const jsonContent = JSON.stringify(jsonData, null, 2);
        const jsonBase64 = Buffer.from(jsonContent).toString("base64");

        await client.dbfs.put({
            path: jsonPath,
            contents: jsonBase64,
            overwrite: true,
        });

        console.log(`✓ JSON file uploaded to ${jsonPath}`);

        // List again to show both files
        const allFiles: any[] = [];
        for await (const file of client.dbfs.list({
            path: dbfsPath,
        })) {
            allFiles.push({
                "Path": file.path,
                "Size (bytes)": file.file_size,
            });
        }

        console.log(`\nAll files in ${dbfsPath}:`);
        console.table(allFiles);

        // Cleanup: Delete the files and directory
        console.log(`\nCleaning up...`);

        await client.dbfs.delete({
            path: dbfsPath,
            recursive: true,
        });

        console.log(`✓ Directory and files deleted`);
    } catch (error) {
        console.error(`✗ Error:`, error);
        process.exit(1);
    }
}

main();
